// Example: Node.js Function validating JWT and group
const jwt = require('jsonwebtoken');
module.exports = async function (context, req) {
  const header = req.headers['authorization'];
  if (!header) return { status: 401, body: 'Missing token' };
  try {
    const token = header.split(' ')[1];
    const decoded = jwt.verify(token, process.env.JWKS, { algorithms: ['RS256'] });
    if (!decoded.groups || !decoded.groups.includes('PartnerUser')) {
      return { status: 403, body: 'Forbidden' };
    }
    return { status: 200, body: 'OK' };
  } catch (e) {
    return { status: 401, body: 'Invalid token' };
  }
}
```

